import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useCart } from '../hooks/usecart';
import { ChevronLeft, MapPin, AlertTriangle, ShieldCheck, CreditCard } from 'lucide-react';

const CheckoutPage = () => {
  const navigate = useNavigate();
  const { items = [] } = useCart();

  // Clean cart items
  const validItems = items.filter(item => item && item.productId && String(item.productId) !== 'undefined');

  // Redirect to cart if empty
  useEffect(() => {
    if (validItems.length === 0) {
      navigate('/cart');
    }
  }, [validItems, navigate]);

  // Form State
  const [formData, setFormData] = useState({
    fullName: '',
    phone: '',
    address1: '',
    address2: '',
    city: '',
    state: '',
    pincode: ''
  });

  // Centered Modal State
  const [showModal, setShowModal] = useState(false);
  const [modalMessage, setModalMessage] = useState('');

  // Math Calculations (Matches your screenshot logic: Subtotal + 18% GST)
  const subtotal = validItems.reduce((acc, item) => {
    const price = Number(item.price) || 0;
    const qty = Number(item.quantity) || 1;
    return acc + (price * qty);
  }, 0);

  const gst = Math.round(subtotal * 0.18);
  const total = subtotal + gst;

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleContinuePayment = () => {
    // 1. Check for missing required fields
    const requiredFields = ['fullName', 'phone', 'address1', 'city', 'state', 'pincode'];
    const missingFields = requiredFields.filter(field => !formData[field].trim());

    if (missingFields.length > 0) {
      setModalMessage('Please fill in all required shipping details to proceed with your order.');
      setShowModal(true);
      return;
    }

    // 2. Validate Phone Number (Basic 10 digit check)
    if (formData.phone.replace(/\D/g, '').length < 10) {
      setModalMessage('Please enter a valid 10-digit phone number.');
      setShowModal(true);
      return;
    }

    // 3. Validate Pincode (6 digits)
    if (formData.pincode.replace(/\D/g, '').length !== 6) {
      setModalMessage('Please enter a valid 6-digit pincode.');
      setShowModal(true);
      return;
    }

    // If everything is perfect, proceed to payment!
    // navigate('/payment', { state: { shippingData: formData, total } });
    console.log("Proceeding to payment with:", formData);
    alert("Validation Passed! Ready to move to Payment Gateway.");
  };

  return (
    <div className="bg-[#f8f9fa] min-h-screen py-8 md:py-12 font-sans relative">

      {/* ========================================================
          🚀 CENTERED VALIDATION MODAL (Frosted Glass Overlay)
          ======================================================== */}
      {showModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/40 backdrop-blur-sm transition-all duration-300">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm p-8 transform transition-all flex flex-col items-center text-center animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-5 shadow-sm border border-red-100">
              <AlertTriangle size={32} strokeWidth={1.5} />
            </div>
            <h3 className="text-xl font-bold text-gray-900 mb-2 tracking-tight">Missing Information</h3>
            <p className="text-sm text-gray-500 mb-8 leading-relaxed px-2">
              {modalMessage}
            </p>
            <button
              onClick={() => setShowModal(false)}
              className="w-full bg-gray-900 text-white font-bold py-4 rounded-xl hover:bg-orange-500 hover:shadow-lg hover:shadow-orange-500/20 active:scale-[0.98] transition-all duration-300 outline-none focus:outline-none"
            >
              GOT IT
            </button>
          </div>
        </div>
      )}

      <div className="container mx-auto px-4 max-w-6xl">

        {/* Navigation Back to Cart */}
        <div className="mb-6">
          <button
            onClick={() => navigate('/cart')}
            className="inline-flex items-center text-sm font-bold text-gray-500 hover:text-orange-500 transition-colors group outline-none focus:outline-none"
          >
            <ChevronLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            Return to Cart
          </button>
        </div>

        <div className="flex items-center mb-8">
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">Checkout</h1>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12 items-start">

          {/* ========================================================
              LEFT COLUMN: PREMIUM SHIPPING FORM
              ======================================================== */}
          <div className="lg:col-span-7 flex flex-col gap-6">
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-6 md:p-10">

              <div className="flex items-center gap-3 mb-8 border-b border-gray-100 pb-5">
                <div className="bg-orange-50 text-orange-500 p-2.5 rounded-full">
                  <MapPin size={24} strokeWidth={1.5} />
                </div>
                <h2 className="text-xl font-bold text-gray-900">Shipping Address</h2>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-5 gap-y-6">

                {/* Full Name */}
                <div className="relative md:col-span-1 group">
                  <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 block">Full Name *</label>
                  <input
                    type="text" name="fullName" value={formData.fullName} onChange={handleInputChange}
                    className="w-full bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl px-4 py-3.5 focus:bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all outline-none"
                    placeholder="John Doe"
                  />
                </div>

                {/* Phone Number */}
                <div className="relative md:col-span-1 group">
                  <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 block">Phone Number *</label>
                  <input
                    type="tel" name="phone" value={formData.phone} onChange={handleInputChange} maxLength="10"
                    className="w-full bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl px-4 py-3.5 focus:bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all outline-none"
                    placeholder="9876543210"
                  />
                </div>

                {/* Address Line 1 */}
                <div className="relative md:col-span-2 group">
                  <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 block">Address Line 1 *</label>
                  <input
                    type="text" name="address1" value={formData.address1} onChange={handleInputChange}
                    className="w-full bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl px-4 py-3.5 focus:bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all outline-none"
                    placeholder="House No., Building Name, Street"
                  />
                </div>

                {/* Address Line 2 */}
                <div className="relative md:col-span-2 group">
                  <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 block">Address Line 2 (Optional)</label>
                  <input
                    type="text" name="address2" value={formData.address2} onChange={handleInputChange}
                    className="w-full bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl px-4 py-3.5 focus:bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all outline-none"
                    placeholder="Locality, Area, Landmark"
                  />
                </div>

                {/* City */}
                <div className="relative md:col-span-1 group">
                  <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 block">City *</label>
                  <input
                    type="text" name="city" value={formData.city} onChange={handleInputChange}
                    className="w-full bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl px-4 py-3.5 focus:bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all outline-none"
                    placeholder="Hyderabad"
                  />
                </div>

                {/* State & Pincode Grid */}
                <div className="md:col-span-1 grid grid-cols-2 gap-4">
                  <div className="relative group">
                    <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 block">State *</label>
                    <input
                      type="text" name="state" value={formData.state} onChange={handleInputChange}
                      className="w-full bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl px-4 py-3.5 focus:bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all outline-none"
                      placeholder="Telangana"
                    />
                  </div>
                  <div className="relative group">
                    <label className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 block">Pincode *</label>
                    <input
                      type="text" name="pincode" value={formData.pincode} onChange={handleInputChange} maxLength="6"
                      className="w-full bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl px-4 py-3.5 focus:bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all outline-none"
                      placeholder="500001"
                    />
                  </div>
                </div>

              </div>

              <div className="mt-10 pt-8 border-t border-gray-100">
                <button
                  onClick={handleContinuePayment}
                  className="w-full md:w-auto bg-[#6f4f36] text-white px-10 py-4 rounded-xl font-bold tracking-wide hover:bg-[#5a3f2a] hover:shadow-lg hover:shadow-[#6f4f36]/30 active:scale-[0.98] transition-all duration-300 outline-none focus:outline-none flex justify-center items-center gap-2"
                >
                  <CreditCard size={20} />
                  Continue to Payment
                </button>
              </div>

            </div>
          </div>

          {/* ========================================================
              RIGHT COLUMN: PREMIUM ORDER SUMMARY
              ======================================================== */}
          <div className="lg:col-span-5 flex flex-col gap-6 md:sticky md:top-28">
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-6 md:p-8">

              <h3 className="text-lg font-bold text-gray-900 mb-6 tracking-tight border-b border-gray-100 pb-4">Order Summary</h3>

              {/* Items List */}
              <div className="flex flex-col gap-4 max-h-[350px] overflow-y-auto pr-2 custom-scrollbar mb-6">
                {validItems.map((item, index) => {
                  const itemPrice = Number(item.price) || 0;
                  const itemQty = Number(item.quantity) || 1;

                  return (
                    <div key={index} className="flex items-center gap-4 group">
                      <div className="w-16 h-16 bg-gray-100 rounded-lg overflow-hidden border border-gray-200 shrink-0 relative">
                        <img
                          src={item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=200&q=80'}
                          alt={item.name}
                          className="w-full h-full object-cover"
                          onError={(e) => { e.target.onerror = null; e.target.src = 'https://images.unsplash.com/photo-1493663284031-b7e3aefcae8e?w=200&q=80'; }}
                        />
                        <div className="absolute -top-2 -right-2 bg-gray-900 text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                          {itemQty}
                        </div>
                      </div>
                      <div className="flex-1 min-w-0">
                        <h4 className="text-sm font-bold text-gray-900 truncate">{item.name || 'Premium Item'}</h4>
                        <p className="text-xs text-gray-500 mt-0.5">Qty: {itemQty}</p>
                      </div>
                      <div className="text-sm font-bold text-gray-900 shrink-0">
                        ₹{(itemPrice * itemQty).toLocaleString('en-IN')}
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Price Breakdown */}
              <div className="space-y-4 pt-4 border-t border-gray-100">
                <div className="flex justify-between items-center text-sm">
                  <span className="text-gray-600 font-medium">Subtotal</span>
                  <span className="text-gray-900 font-bold">₹{subtotal.toLocaleString('en-IN')}</span>
                </div>
                <div className="flex justify-between items-center text-sm">
                  <span className="text-gray-600 font-medium">Shipping</span>
                  <span className="text-green-600 font-bold tracking-wide">Free</span>
                </div>
                <div className="flex justify-between items-center text-sm">
                  <span className="text-gray-600 font-medium">GST (18%)</span>
                  <span className="text-gray-900 font-bold">₹{gst.toLocaleString('en-IN')}</span>
                </div>
              </div>

              {/* Total */}
              <div className="mt-6 pt-6 border-t border-gray-200 border-dashed">
                <div className="flex justify-between items-center">
                  <span className="text-xl font-black text-gray-900 tracking-tight">Total</span>
                  <span className="text-2xl font-black text-gray-900 tracking-tight">₹{total.toLocaleString('en-IN')}</span>
                </div>
              </div>

            </div>

            {/* Trust Badge */}
            <div className="flex items-center justify-center gap-2 text-sm text-gray-500 font-medium bg-green-50/50 py-3 rounded-xl border border-green-100">
              <ShieldCheck size={18} className="text-green-600" />
              <span>100% Safe & Secure Checkout</span>
            </div>

          </div>

        </div>
      </div>

      <style jsx="true">{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f1f1; 
          border-radius: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #d1d5db; 
          border-radius: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #9ca3af; 
        }
      `}</style>
    </div>
  );
};

export default CheckoutPage;
